import json
import os
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
from datetime import datetime

PROJECT_ID = os.environ.get('GCP_PROJECT', 'your-project-id')
PUBSUB_TOPIC = os.environ.get('PUBSUB_TOPIC', 'file-processed')

storage_client = storage.Client()
db = firestore.Client()
publisher = pubsub_v1.PublisherClient()

@functions_framework.cloud_event
def process_storage_file(cloud_event):
    data = cloud_event.data
    
    bucket_name = data['bucket']
    file_name = data['name']
    
    try:
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        file_content = blob.download_as_text()
        file_size = blob.size
        content_type = blob.content_type
        created_time = blob.time_created
        
        document_data = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'file_size': file_size,
            'content_type': content_type,
            'created_time': created_time,
            'processed_time': firestore.SERVER_TIMESTAMP,
            'content_preview': file_content[:500] if file_content else '',
            'status': 'processed'
        }
        
        doc_ref = db.collection('processed_files').document()
        doc_ref.set(document_data)
        
        pubsub_message = {
            'document_id': doc_ref.id,
            'file_name': file_name,
            'bucket_name': bucket_name,
            'file_size': file_size,
            'event_type': 'file_processed',
            'timestamp': datetime.utcnow().isoformat()
        }
        
        topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
        message_bytes = json.dumps(pubsub_message).encode('utf-8')
        future = publisher.publish(topic_path, message_bytes)
        message_id = future.result()
        
        print(f'Successfully processed file: {file_name}')
        print(f'Firestore document ID: {doc_ref.id}')
        print(f'Pub/Sub message ID: {message_id}')
        
        return {'status': 'success', 'document_id': doc_ref.id, 'message_id': message_id}
        
    except Exception as e:
        error_message = f'Error processing file {file_name}: {str(e)}'
        print(error_message)
        
        error_doc = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'error': str(e),
            'timestamp': firestore.SERVER_TIMESTAMP,
            'status': 'failed'
        }
        db.collection('processing_errors').add(error_doc)
        
        raise


@functions_framework.http
def process_file_http(request):
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket' not in request_json or 'file' not in request_json:
        return {'error': 'Missing bucket or file parameter'}, 400
    
    bucket_name = request_json['bucket']
    file_name = request_json['file']
    
    try:
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            return {'error': f'File {file_name} not found in bucket {bucket_name}'}, 404
        
        file_content = blob.download_as_text()
        file_size = blob.size
        content_type = blob.content_type
        
        document_data = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'file_size': file_size,
            'content_type': content_type,
            'processed_time': firestore.SERVER_TIMESTAMP,
            'content_preview': file_content[:500] if file_content else '',
            'status': 'processed',
            'trigger': 'http'
        }
        
        doc_ref = db.collection('processed_files').document()
        doc_ref.set(document_data)
        
        pubsub_message = {
            'document_id': doc_ref.id,
            'file_name': file_name,
            'bucket_name': bucket_name,
            'file_size': file_size,
            'event_type': 'file_processed_http',
            'timestamp': datetime.utcnow().isoformat()
        }
        
        topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
        message_bytes = json.dumps(pubsub_message).encode('utf-8')
        future = publisher.publish(topic_path, message_bytes)
        message_id = future.result()
        
        return {
            'status': 'success',
            'document_id': doc_ref.id,
            'message_id': message_id,
            'file_name': file_name,
            'file_size': file_size
        }, 200
        
    except Exception as e:
        error_message = f'Error processing file {file_name}: {str(e)}'
        print(error_message)
        
        return {'error': error_message}, 500


def list_processed_files(limit=10):
    docs = db.collection('processed_files').order_by('processed_time', direction=firestore.Query.DESCENDING).limit(limit).stream()
    
    files = []
    for doc in docs:
        file_data = doc.to_dict()
        file_data['id'] = doc.id
        files.append(file_data)
    
    return files


def get_file_stats(bucket_name):
    query = db.collection('processed_files').where('bucket_name', '==', bucket_name)
    docs = query.stream()
    
    total_files = 0
    total_size = 0
    
    for doc in docs:
        data = doc.to_dict()
        total_files += 1
        total_size += data.get('file_size', 0)
    
    return {
        'bucket_name': bucket_name,
        'total_files': total_files,
        'total_size_bytes': total_size
    }